// 滑块更新阈值显示
document.getElementById('llm-threshold-slider').addEventListener('input', function() {
    const v = this.value;
    document.getElementById('llm-threshold-val').textContent = v;
    document.getElementById('llm-threshold-display').textContent = v;
});

async function startLlmScreen() {
    const threshold = parseInt(document.getElementById('llm-threshold-slider').value);

    // 显示加载
    document.getElementById('llm-start-btn').disabled = true;
    document.getElementById('llm-loading-box').classList.remove('d-none');
    document.getElementById('llm-result-box').classList.add('d-none');
    document.getElementById('llm-error-box').classList.add('d-none');

    try {
        // 发起异步 LLM 初筛（立即返回）
        const resp = await fetch(LLM_SCREEN_URL, {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({threshold: threshold}),
        });
        const data = await resp.json();

        if (!data.success) {
            document.getElementById('llm-loading-box').classList.add('d-none');
            document.getElementById('llm-error-box').classList.remove('d-none');
            document.getElementById('llm-error-box').textContent = '启动失败: ' + (data.error || '未知错误');
            document.getElementById('llm-start-btn').disabled = false;
            return;
        }

        if (data.total === 0) {
            document.getElementById('llm-loading-box').classList.add('d-none');
            document.getElementById('llm-result-box').classList.remove('d-none');
            document.getElementById('llm-result-icon').className = 'bi bi-check-circle-fill text-success fs-5';
            document.getElementById('llm-result-title').textContent = '没有符合条件的用户（评分均 < ' + threshold + '）';
            document.getElementById('llm-start-btn').disabled = false;
            return;
        }

        // 轮询进度
        const PROGRESS_TEXT = document.getElementById('llm-progress-text');
        const PROGRESS_BATCH = document.getElementById('llm-progress-batch');

        function updateProgress(text, done, total) {
            if (PROGRESS_TEXT) PROGRESS_TEXT.textContent = text;
            if (PROGRESS_BATCH && total > 0) PROGRESS_BATCH.textContent = done + '/' + total;
        }

        updateProgress('正在初始化...', 0, 0);

        llmScreenPollTimer = setInterval(async () => {
            try {
                const sResp = await fetch(LLM_SCREEN_STATUS_URL);
                const sData = await sResp.json();
                const st = sData.data || {};

                const done = st.done_batches || 0;
                const total = st.total_batches || 0;
                updateProgress(st.progress || '分析中...', done, total);

                if (st.status === 'done') {
                    clearInterval(llmScreenPollTimer);
                    llmScreenPollTimer = null;
                    document.getElementById('llm-loading-box').classList.add('d-none');
                    document.getElementById('llm-result-box').classList.remove('d-none');
                    document.getElementById('llm-result-icon').className = 'bi bi-check-circle-fill text-success fs-5';
                    document.getElementById('llm-result-title').textContent =
                        'LLM 初筛完成！成功 ' + (st.success_count || 0) + '/' + (st.total || 0) + ' 个用户';
                    document.getElementById('llm-r-total').textContent = st.total || '--';
                    document.getElementById('llm-r-analyzed').textContent = st.success_count || '--';
                    let identified = 0;
                    if (st.identified_types) {
                        identified = Object.values(st.identified_types).reduce((a, b) => a + b, 0);
                    }
                    document.getElementById('llm-r-identified').textContent = identified || '--';
                    document.getElementById('llm-start-btn').disabled = false;
                    // 自动刷新页面
                    setTimeout(() => location.reload(), 2500);
                } else if (st.status === 'error') {
                    clearInterval(llmScreenPollTimer);
                    llmScreenPollTimer = null;
                    document.getElementById('llm-loading-box').classList.add('d-none');
                    document.getElementById('llm-error-box').classList.remove('d-none');
                    document.getElementById('llm-error-box').textContent = '初筛失败: ' + (st.error || '未知错误');
                    document.getElementById('llm-start-btn').disabled = false;
                }
            } catch (pollErr) {
                // 忽略轮询中的临时网络错误，继续重试
                console.warn('LLM screen poll error:', pollErr);
            }
        }, 2000);

    } catch (err) {
        document.getElementById('llm-loading-box').classList.add('d-none');
        document.getElementById('llm-error-box').classList.remove('d-none');
        document.getElementById('llm-error-box').textContent = '网络错误: ' + err.message;
        document.getElementById('llm-start-btn').disabled = false;
    }
}

