// ---- 单用户 LLM 分析（弹窗内原地刷新） ----
async function runLLMAnalyzeInModal(mid) {
    const btn = document.getElementById('llm-analyze-btn');
    if (!btn) return;
    btn.disabled = true;
    btn.innerHTML = '<span class="spinner-border spinner-border-sm"></span> LLM 分析中...';

    try {
        const resp = await fetch('/api/video/BV1RGVY6nELf/user/' + mid + '/llm-analyze', { method: 'POST' });
        const data = await resp.json();
        if (data.success) {
            showToast(`LLM 分析完成: ${data.llm_type_name || '未知'} (${data.llm_confidence}%)`, 'success');
            // 原地刷新：重新渲染弹窗
            const idx = scoredUsers.findIndex(u => String(u.mid) === String(mid));
            if (idx >= 0) {
                const r = await fetch(`/api/video/BV1RGVY6nELf/user/${mid}/detail`);
                if (r.ok) {
                    const d = await r.json();
                    if (d.success) {
                        scoredUsers[idx] = Object.assign({}, scoredUsers[idx], d.data);
                    }
                }
                showUserDetail(idx);
            } else {
                location.reload();
            }
        } else {
            showToast('LLM 分析失败: ' + (data.error || '未知错误'), 'error');
            btn.disabled = false;
            btn.innerHTML = '<i class="bi bi-cpu"></i> 重试 LLM 分析';
        }
    } catch (err) {
        showToast('网络错误: ' + err.message, 'error');
        btn.disabled = false;
        btn.innerHTML = '<i class="bi bi-cpu"></i> 重试 LLM 分析';
    }
}

// ---- 单用户 AICU 深度分析（弹窗内原地刷新） ----
async function runAICUAnalyzeInModal(mid) {
    const btn = document.getElementById('aicu-analyze-btn');
    if (!btn) return;
    if (!confirm(`对 MID=${mid} 执行 AICU 深度分析？\n会爬取该用户历史评论，预计 5-20 秒。`)) return;

    btn.disabled = true;
    btn.innerHTML = '<span class="spinner-border spinner-border-sm"></span> 深度分析中...';

    try {
        const resp = await fetch('/api/video/BV1RGVY6nELf/user/' + mid + '/deep-analyze', { method: 'POST' });
        const data = await resp.json();
        console.log('[AICU] deep-analyze response:', data);
        if (data.success) {
            const parts = [];
            if (data.deep_analyzed) parts.push(`深度类型: ${data.deep_type_name || '正常用户'}`);
            if (data.aicu_comment_count) parts.push(`历史评论: ${data.aicu_comment_count}条`);
            if (data.aicu_device) parts.push(`设备: ${data.aicu_device}`);
            if (data.aicu_waf_blocked) parts.push(`⚠️ AICU API 被 WAF 拦截`);
            showToast('AICU 分析完成: ' + (parts.join(', ') || '完成'), 'success');
            // 原地刷新弹窗
            const idx = scoredUsers.findIndex(u => String(u.mid) === String(mid));
            console.log('[AICU] findIndex for mid=' + mid + ' → idx=' + idx);
            if (idx >= 0) {
                const r = await fetch(`/api/video/BV1RGVY6nELf/user/${mid}/detail`);
                console.log('[AICU] detail API status:', r.status);
                if (r.ok) {
                    const d = await r.json();
                    console.log('[AICU] detail data keys:', Object.keys(d.data || {}));
                    console.log('[AICU] deep_analyzed before merge:', scoredUsers[idx].deep_analyzed);
                    if (d.success) {
                        scoredUsers[idx] = Object.assign({}, scoredUsers[idx], d.data);
                        console.log('[AICU] deep_analyzed after merge:', scoredUsers[idx].deep_analyzed);
                        console.log('[AICU] deep_type_id after merge:', scoredUsers[idx].deep_type_id);
                    }
                }
                showUserDetail(idx);
            } else {
                console.log('[AICU] mid not in scoredUsers, force reload');
                location.reload();
            }
        } else {
            showToast('AICU 分析失败: ' + (data.error || '未知错误'), 'error');
            btn.disabled = false;
            btn.innerHTML = '<i class="bi bi-search"></i> 重试深度分析';
        }
    } catch (err) {
        showToast('网络错误: ' + err.message, 'error');
        btn.disabled = false;
        btn.innerHTML = '<i class="bi bi-search"></i> 重试深度分析';
    }
}

// ---- 用户详情 ----
function showUserDetail(index) {
    const user = scoredUsers[index];
    if (!user) return;

    const modalTitle = document.getElementById('userDetailTitle');
    const modalBody = document.getElementById('userDetailBody');

    modalTitle.innerHTML = `<i class="bi bi-person-badge"></i> ${user.uname || '未知用户'} <small class="text-white-50">MID: ${user.mid}</small>`;

    // --- Risk & Score row ---
    const riskColor = user.score >= 70 ? 'danger' : (user.score >= 40 ? 'warning' : 'success');
    const riskLabel = user.score >= 70 ? '高风险' : (user.score >= 40 ? '中风险' : '低风险');

    // --- Feature breakdown ---
    let featuresHtml = '';
    if (user.features) {
        const sorted = Object.entries(user.features)
            .filter(([k]) => FEATURE_NAMES_ALL[k])
            .sort((a, b) => b[1] - a[1]);
        featuresHtml = sorted.map(([key, val]) => {
            const pct = Math.round(val);
            const barColor = pct >= 70 ? 'bg-danger' : (pct >= 40 ? 'bg-warning' : 'bg-secondary');
            const fname = FEATURE_NAMES_ALL[key] || key;
            const fdesc = FEATURE_DESCRIPTIONS[fname] || '';
            return `<div class="d-flex align-items-center mb-2">
                <span class="text-nowrap me-1" style="width:110px;font-size:0.85em">
                    ${fname}
                    <i class="bi bi-info-circle text-muted" style="font-size:0.7em;cursor:help"
                       data-bs-toggle="tooltip" data-bs-placement="top"
                       title="${fdesc}"></i>
                </span>
                <div class="flex-grow-1 me-2" style="height:8px">
                    <div class="progress" style="height:8px"><div class="progress-bar ${barColor}" style="width:${Math.min(pct,100)}%"></div></div>
                </div>
                <span class="text-muted small" style="width:35px;text-align:right">${pct}%</span>
            </div>`;
        }).join('');
    }

    // --- LLM analysis ---
    let llmHtml = '';
    if (user.llm_analyzed) {
        const typeId = user.llm_type_id || 0;
        if (typeId > 0) {
            // 判定为水军类型
            const typeColor = LLM_TYPE_COLORS[typeId] || '#666';
            llmHtml = `<div class="card mb-3 border-start border-4" style="border-left-color:${typeColor}">
                <div class="card-body">
                    <h6 class="card-title">
                        <span class="badge" style="background:${typeColor};color:#fff">${user.llm_type_name}</span>
                        <span class="ms-2 text-muted small">LLM 置信度: ${user.llm_confidence}%</span>
                    </h6>
                    <p class="card-text small mb-2">${(user.llm_reasoning || '无详细推理').replace(/</g,'&lt;')}</p>
                    <button class="btn btn-sm btn-outline-primary" id="llm-analyze-btn" onclick="runLLMAnalyzeInModal(${user.mid})">
                        <i class="bi bi-arrow-repeat"></i> 重新 LLM 分析
                    </button>
                </div>
            </div>`;
        } else {
            // 判定为正常用户
            llmHtml = `<div class="card mb-3 border-start border-4" style="border-left-color:#198754">
                <div class="card-body">
                    <h6 class="card-title">
                        <span class="badge bg-success">正常用户</span>
                        <span class="ms-2 text-muted small">LLM 置信度: ${user.llm_confidence}%</span>
                    </h6>
                    <p class="card-text small mb-2">${(user.llm_reasoning || 'LLM 判定该用户行为正常，未发现水军特征').replace(/</g,'&lt;')}</p>
                    <button class="btn btn-sm btn-outline-primary" id="llm-analyze-btn" onclick="runLLMAnalyzeInModal(${user.mid})">
                        <i class="bi bi-arrow-repeat"></i> 重新 LLM 分析
                    </button>
                </div>
            </div>`;
        }
    } else {
        llmHtml = `<div class="card mb-3 border-start border-4" style="border-left-color:#999">
            <div class="card-body">
                <h6 class="card-title text-muted"><i class="bi bi-robot"></i> LLM 未分析</h6>
                <p class="card-text small text-muted mb-2">该用户评分未达到 LLM 分析阈值，或 LLM 未启用</p>
                <button class="btn btn-sm btn-outline-primary" id="llm-analyze-btn" onclick="runLLMAnalyzeInModal(${user.mid})">
                    <i class="bi bi-cpu"></i> 执行 LLM 分析
                </button>
            </div>
        </div>`;
    }

    // --- AICU Deep Analysis ---
    let deepHtml = '';
    if (user.deep_analyzed && user.deep_type_id > 0) {
        // 判定为水军（type_id 1-8）
        const dTypeColor = LLM_TYPE_COLORS[user.deep_type_id] || '#666';
        const evidenceHtml = (user.deep_key_evidence || []).map(e =>
            `<li class="small">${(e||'').replace(/</g,'&lt;')}</li>`
        ).join('') || '<li class="small text-muted">无具体证据</li>';

        const confirmedBadge = user.deep_risk_confirmed
            ? '<span class="badge bg-danger ms-1"><i class="bi bi-exclamation-triangle"></i> 深度确认高风险</span>'
            : '<span class="badge bg-warning text-dark ms-1"><i class="bi bi-question-circle"></i> 待进一步确认</span>';

        deepHtml = `<div class="card mb-3 border-start border-4" style="border-left-color:${dTypeColor}">
            <div class="card-body">
                <h6 class="card-title">
                    <span class="badge" style="background:${dTypeColor};color:#fff">${user.deep_type_name}</span>
                    <span class="ms-2 text-muted small">AICU 深度置信度: ${user.deep_confidence || 0}%</span>
                    ${confirmedBadge}
                </h6>
                <p class="card-text small mb-2">${(user.deep_reasoning || '无详细推理').replace(/</g,'&lt;')}</p>
                <div class="mt-2"><strong class="small"><i class="bi bi-journal-text"></i> 关键证据:</strong></div>
                <ul class="mb-3 ps-3">${evidenceHtml}</ul>
                <button class="btn btn-sm btn-outline-warning" id="aicu-analyze-btn" onclick="runAICUAnalyzeInModal(${user.mid})">
                    <i class="bi bi-arrow-repeat"></i> 重新 AICU 深度分析
                </button>
            </div>
        </div>`;

        // AICU metadata（始终显示，只要做过深度分析）
        if (user.deep_analyzed) {
            const aicuParts = [];
            if (user.aicu_comment_count != null && user.aicu_comment_count > 0) aicuParts.push(`历史评论: ${user.aicu_comment_count} 条`);
            else if (user.aicu_comment_count === 0) aicuParts.push(`历史评论: 0 条（无历史评论）`);
            if (user.aicu_device) aicuParts.push(`设备: ${user.aicu_device}`);
            if (user.aicu_names && user.aicu_names.length > 0) aicuParts.push(`曾用名: ${user.aicu_names.join(', ')}`);
            const stats = user.aicu_stats || {};
            if (Object.keys(stats).length > 0) {
                const st = [];
                if (stats.total_comments) st.push(`总评${stats.total_comments}`);
                if (stats.sign) st.push(`签名"${stats.sign}"`);
                if (st.length > 0) aicuParts.push(st.join('，'));
            }
            let aicuNote = aicuParts.length > 0 ? aicuParts.join(' | ') : '已抓取，但无显著特征数据';
            if (user.aicu_waf_blocked) aicuNote = '⚠️ AICU API 被 WAF 拦截，无法获取历史数据（LLM 仍基于本地评论完成分析）';
            deepHtml += `<div class="row mb-3">
                <div class="col-md-12"><small class="text-muted">📊 AICU 深度数据:</small><br><strong>${aicuNote}</strong></div>
            </div>`;
        }
    } else if (user.deep_analyzed) {
        // 已分析但 type_id=0 → LLM 判定为正常用户/非水军
        deepHtml = `<div class="card mb-3 border-start border-4" style="border-left-color:#28a745">
            <div class="card-body">
                <h6 class="card-title">
                    <span class="badge bg-success"><i class="bi bi-check-circle"></i> ${user.deep_type_name || '正常用户'}</span>
                    <span class="ms-2 text-muted small">AICU 深度置信度: ${user.deep_confidence || 0}%</span>
                    <span class="badge bg-success ms-1"><i class="bi bi-shield-check"></i> 非水军</span>
                </h6>
                <p class="card-text small mb-2">${(user.deep_reasoning || '经 AICU 历史数据深度分析，该用户未发现水军行为特征。').replace(/</g,'&lt;')}</p>
                <button class="btn btn-sm btn-outline-warning" id="aicu-analyze-btn" onclick="runAICUAnalyzeInModal(${user.mid})">
                    <i class="bi bi-arrow-repeat"></i> 重新 AICU 深度分析
                </button>
            </div>
        </div>`;

        // AICU metadata（正常用户也显示，始终渲染）
        if (user.deep_analyzed) {
            const aicuParts = [];
            if (user.aicu_comment_count) aicuParts.push(`历史评论: ${user.aicu_comment_count} 条`);
            if (user.aicu_device) aicuParts.push(`设备: ${user.aicu_device}`);
            if (user.aicu_names && user.aicu_names.length > 0) aicuParts.push(`曾用名: ${user.aicu_names.join(', ')}`);
            const stats = user.aicu_stats || {};
            if (Object.keys(stats).length > 0) {
                const st = [];
                if (stats.total_comments) st.push(`总评${stats.total_comments}`);
                if (stats.signs) st.push(`签名"${stats.signs}"`);
                if (st.length > 0) aicuParts.push(st.join('，'));
            }
            let aicuNote = aicuParts.length > 0 ? aicuParts.join(' | ') : '已抓取，但无显著特征数据';
            if (user.aicu_waf_blocked) aicuNote = '⚠️ AICU API 被 WAF 拦截，无法获取历史数据（LLM 仍基于本地评论完成分析）';
            deepHtml += `<div class="row mb-3">
                <div class="col-md-12"><small class="text-muted">📊 AICU 深度数据:</small><br><strong>${aicuNote}</strong></div>
            </div>`;
        }
    } else {
        // 未分析 → 显示执行按钮
        deepHtml = `<div class="card mb-3 border-start border-4" style="border-left-color:#ccc">
            <div class="card-body">
                <h6 class="card-title text-muted"><i class="bi bi-search"></i> AICU 深度分析</h6>
                <p class="card-text small text-muted mb-2">未启用深度分析，或该用户评分未达到深度分析阈值</p>
                <button class="btn btn-sm btn-outline-warning" id="aicu-analyze-btn" onclick="runAICUAnalyzeInModal(${user.mid})">
                    <i class="bi bi-search"></i> 执行 AICU 深度分析
                </button>
            </div>
        </div>`;
    }

    // --- Sample comments ---
    let commentsHtml = '';
    if (user.sample_comments && user.sample_comments.length > 0) {
        commentsHtml = `<div class="card mb-3">
            <div class="card-header small"><i class="bi bi-chat-left-text"></i> 样本评论 (${user.sample_comments.length} 条)</div>
            <div class="card-body p-0" style="max-height:300px;overflow-y:auto">
                ${user.sample_comments.map((c,i) => `
                    <div class="p-2 border-bottom small">
                        <span class="text-muted">#${i+1}</span>&nbsp;
                        ${(c.content||c||'').replace(/</g,'&lt;').substring(0,200)}
                    </div>
                `).join('')}
            </div>
        </div>`;
    }

    // --- Metadata ---
    const reportTime = '2026-06-01T15:44:16';

    // --- Assemble modal body ---
    modalBody.innerHTML = `
        <div class="row mb-3">
            <div class="col-md-4"><div class="border rounded p-2 text-center"><div class="text-muted small">综合评分</div><h3 class="text-${riskColor} mb-0">${user.score}</h3></div></div>
            <div class="col-md-4"><div class="border rounded p-2 text-center"><div class="text-muted small">风险等级</div><h4 class="mb-0"><span class="badge bg-${riskColor} fs-6">${riskLabel}</span></h4></div></div>
            <div class="col-md-4"><div class="border rounded p-2 text-center"><div class="text-muted small">Lv${user.level} · ${user.comment_count}条评论</div><h5 class="mb-0 text-muted">${reportTime}</h5></div></div>
        </div>

        <div class="mb-3">
            <button class="btn btn-sm btn-outline-danger" onclick="collectWaterArmy(${user.mid}, '${(user.uname||'').replace(/'/g,"\\'")}', ${user.score}, '${riskLabel}', 'BV1RGVY6nELf')" id="wa-collect-btn-${user.mid}">
                <i class="bi bi-shield-exclamation"></i> 收录为水军账号
            </button>
            <a href="https://space.bilibili.com/${user.mid}" target="_blank" class="btn btn-sm btn-outline-secondary ms-1">
                <i class="bi bi-box-arrow-up-right"></i> B站主页
            </a>
        </div>

        <h6><i class="bi bi-bar-chart-steps"></i> 17维特征评分 <small class="text-muted">(鼠标悬停 <i class="bi bi-info-circle"></i> 查看含义)</small></h6>
        <div class="mb-3">${featuresHtml}</div>

        <h6><i class="bi bi-robot"></i> LLM 初筛分析</h6>
        ${llmHtml}

        <h6><i class="bi bi-search"></i> AICU 深度分析 <small class="text-muted">(历史评论/弹幕回溯)</small></h6>
        ${deepHtml}

        ${commentsHtml}
    `;

    // Show modal via Bootstrap（复用单例，避免 backdrop 泄漏）
    const modalEl = document.getElementById('userDetailModal');
    const existing = bootstrap.Modal.getInstance(modalEl);
    if (existing) existing.dispose();
    const modal = new bootstrap.Modal(modalEl);
    modal.show();

    // 初始化特征说明 tooltips（动态渲染后需要手动激活）
    setTimeout(() => {
        const tooltips = modalBody.querySelectorAll('[data-bs-toggle="tooltip"]');
        tooltips.forEach(el => {
            const existing = bootstrap.Tooltip.getInstance(el);
            if (existing) existing.dispose();
            new bootstrap.Tooltip(el, { container: 'body' });
        });
    }, 300);
}

// ---- 删除当前视频数据 ----
async function refreshVideoData() {
    const btn = document.getElementById('btn-refresh');
    const status = document.getElementById('refresh-status');
    if (!btn || !status) return;

    // 禁用按钮，显示加载状态
    btn.disabled = true;
    btn.innerHTML = '<span class="spinner-border spinner-border-sm"></span> 刷新中...';
    status.style.display = 'inline';
    status.textContent = '正在注入种子并启动爬虫...';

    try {
        const resp = await fetch('/api/video/BV1RGVY6nELf/refresh', { method: 'POST' });
        const data = await resp.json();

        if (data.success) {
            const msg = data.message || '刷新请求已提交';
            status.textContent = msg + '，约 30-60 秒后自动刷新页面查看新数据...';
            showToast('刷新请求已提交，爬虫正在运行中', 'success');

            // 轮询等待爬虫完成，最多等 90 秒
            let waited = 0;
            const pollInterval = 3000;
            const maxWait = 90000;

            const poll = async () => {
                const sresp = await fetch('/api/crawler/status');
                const sdata = await sresp.json();
                const spiders = sdata.data?.spiders || {};
                const videoRunning = spiders.bilibili_video?.status === 'running';
                const commentRunning = spiders.bilibili_comment?.status === 'running';

                if (!videoRunning && !commentRunning) {
                    // 爬虫已停止，刷新页面
                    status.textContent = '爬虫已完成，正在刷新页面...';
                    setTimeout(() => location.reload(), 500);
                    return;
                }

                waited += pollInterval;
                if (waited >= maxWait) {
                    status.textContent = '等待超时，请手动刷新页面查看';
                    btn.disabled = false;
                    btn.innerHTML = '<i class="bi bi-arrow-repeat"></i> 刷新数据';
                    return;
                }

                status.textContent = `爬虫运行中... 已等待 ${Math.round(waited/1000)}s`;
                setTimeout(poll, pollInterval);
            };

            setTimeout(poll, 2000); // 等2秒让爬虫进程启动
        } else {
            status.textContent = '刷新失败: ' + (data.message || '未知错误');
            showToast(data.message || '刷新失败', 'error');
            btn.disabled = false;
            btn.innerHTML = '<i class="bi bi-arrow-repeat"></i> 刷新数据';
        }
    } catch (err) {
        status.textContent = '请求失败: ' + err.message;
        showToast('刷新请求失败: ' + err.message, 'error');
        btn.disabled = false;
        btn.innerHTML = '<i class="bi bi-arrow-repeat"></i> 刷新数据';
    }
}

function deleteThisVideo() {
    const title = '迅好物——华硕';
    confirmDelete(
        `确定要删除「${title || 'BV1RGVY6nELf'}」的所有数据吗？\n\n这将删除：\n  - 视频信息\n  - 1281 条评论数据\n  - 分析报告（如有）\n\n此操作不可撤销！`,
        () => fetch('/api/data/video/BV1RGVY6nELf', { method: 'DELETE' })
            .then(r => r.json())
            .then(d => {
                if (d.success) {
                    showToast(d.message, 'success');
                    setTimeout(() => { window.location.href = '/'; }, 800);
                } else {
                    showToast(d.message || '删除失败', 'error');
                    throw new Error(d.message);
                }
            })
    );
}

// ---- 账号详情 Modal 关闭时强制清理 backdrop（防止残留黑色蒙版） ----
document.getElementById('userDetailModal').addEventListener('hidden.bs.modal', () => {
    document.querySelectorAll('.modal-backdrop').forEach(el => el.remove());
    document.body.classList.remove('modal-open');
    document.body.style.removeProperty('overflow');
    document.body.style.removeProperty('padding-right');
});

// ---- 收录水军账号 ----
function collectWaterArmy(mid, uname, score, riskLevel, bvid) {
    const features = {};
    // 从当前 Modal 的特征进度条中提取
    document.querySelectorAll('#userDetailBody .progress-bar').forEach(bar => {
        const row = bar.closest('.d-flex');
        if (!row) return;
        const label = row.querySelector('.text-nowrap')?.textContent?.trim();
        const pct = parseFloat(row.querySelector('.text-muted.small')?.textContent || '0');
        if (label && label.startsWith('F')) {
            features[label] = pct / 100;  // 百分比还原为 0-1
        }
    });

    const reason = {
        type: "manual_mark",
        bvid: bvid,
        score: score,
        summary: `手动标记: 综合评分 ${score.toFixed(0)}, 风险等级 ${riskLevel}`,
        feature_scores: features,
    };

    const btn = document.getElementById('wa-collect-btn-' + mid);
    if (btn) { btn.disabled = true; btn.innerHTML = '<i class="bi bi-hourglass-split"></i> 收录中...'; }

    fetch('/api/water-army/add', {
        method: 'POST',
        headers: {'Content-Type': 'application/json'},
        body: JSON.stringify({
            mid: mid, uname: uname, score: score,
            risk_level: riskLevel === '高风险' ? 'high' : (riskLevel === '中风险' ? 'medium' : 'low'),
            bvid: bvid, reason: reason,
        })
    }).then(r => r.json()).then(d => {
        if (btn) { btn.disabled = false; btn.innerHTML = '<i class="bi bi-shield-exclamation"></i> 收录为水军账号'; }
        showToast(d.message, d.success ? 'success' : 'error');
        if (d.success && btn) {
            btn.className = 'btn btn-sm btn-success';
            btn.innerHTML = '<i class="bi bi-check-circle"></i> 已收录';
            btn.disabled = true;
        }
    }).catch(() => {
        if (btn) { btn.disabled = false; btn.innerHTML = '<i class="bi bi-shield-exclamation"></i> 收录为水军账号'; }
        showToast('网络错误', 'error');
    });
}

// ---- 收录UP主至水军账号 (视频详情页) ----
function addUPToWaterArmy(mid, uname) {
    if (!mid || mid <= 0) return;
    if (!confirm(`确定将 UP主「${uname}」(UID: ${mid}) 收录至水军账号库吗？`)) return;

    fetch('/api/water-army/add', {
        method: 'POST',
        headers: {'Content-Type': 'application/json'},
        body: JSON.stringify({
            mid: mid,
            uname: uname,
            score: 50,
            risk_level: 'medium',
            bvid: 'BV1RGVY6nELf',
            reason: `视频 BV1RGVY6nELf 的分析中手动标记UP主`,
        })
    }).then(r => r.json()).then(d => {
        showToast(d.message, d.success ? 'success' : 'error');
    }).catch(() => {
        showToast('网络错误', 'error');
    });
}
